const account=($('Ensure account & check').first().json.resolved_account)||$('Prep').first().json.account;
const accId=$('Ensure account & check').first().json.account_id;
const items=$json.data.boards[0].items_page.items;
const al=account.toLowerCase();
const g=(cv,id)=>{const c=cv.find(x=>x.id===id);return c&&c.text!=null&&c.text!==''?c.text:null;};
const q=s=>(s===null||s===undefined||s==='')?'NULL':"'"+String(s).replace(/'/g,"''")+"'";
const num=s=>{if(s===null||s===undefined||s==='')return null;const v=parseFloat(String(s).replace(/[^0-9.\-]/g,''));return isNaN(v)?null:v;};
const match=it=>{const gt=(it.group&&it.group.title?it.group.title:'').toLowerCase();return gt&&(gt.includes(al)||al.includes(gt));};
const sowVal=it=>{let sum=0,any=false;(it.subitems||[]).forEach(su=>{const v=num(g(su.column_values,'numbers'));if(v!==null){sum+=v;any=true;}});return any?Math.round(sum*100)/100:null;};
const rows=items.filter(match).map(it=>{const c=it.column_values;const val=sowVal(it);return '('+q(it.id)+','+q(it.name)+','+q(account)+','+"'"+accId+"'"+','+(val===null?'NULL':val)+','+q(g(c,'date'))+'::date,'+q(g(c,'date6'))+'::date,'+q(g(c,'sow_status'))+','+q(g(c,'status'))+',now())';});
const sql=rows.length?'INSERT INTO projects (monday_item_id,name,account_name,account_id,sow_value,start_date,end_date,sow_status,commercial_model,last_verified) VALUES '+rows.join(',')+' ON CONFLICT (monday_item_id) DO UPDATE SET account_id=EXCLUDED.account_id,sow_value=EXCLUDED.sow_value,sow_status=EXCLUDED.sow_status,last_verified=now();':"SELECT 'no sows matched' AS note;";
return [{json:{sql,matched:rows.length}}];
